<script lang="ts">
	import { onMount } from 'svelte';
	import { fly, fade } from 'svelte/transition';

	// State for triggering client-side entrance animations
	let mounted = $state(false);

	// Typing effect state
	const roles = ['Web Developer', 'Chatbot Developer', 'Automation Specialist'];
	let currentRoleIdx = $state(0);
	let currentText = $state('');
	let isDeleting = $state(false);
	let typingSpeed = $state(100);

	onMount(() => {
		mounted = true;

		let timer: number;
		const tick = () => {
			const fullRole = roles[currentRoleIdx];
			if (isDeleting) {
				currentText = fullRole.substring(0, currentText.length - 1);
				typingSpeed = 50; // Speed of deletion
			} else {
				currentText = fullRole.substring(0, currentText.length + 1);
				typingSpeed = 100; // Speed of typing
			}

			if (!isDeleting && currentText === fullRole) {
				typingSpeed = 2000; // Pause at end of text
				isDeleting = true;
			} else if (isDeleting && currentText === '') {
				isDeleting = false;
				currentRoleIdx = (currentRoleIdx + 1) % roles.length;
				typingSpeed = 500; // Pause before typing next word
			}

			timer = setTimeout(tick, typingSpeed) as unknown as number;
		};

		timer = setTimeout(tick, typingSpeed) as unknown as number;
		return () => clearTimeout(timer);
	});

