{#if mounted}
	<div class="sidebar-content" in:fly={{ x: -40, duration: 1000, delay: 100 }}>
		<!-- Header Area: Pic & Role -->
		<div class="profile-header">
			<div class="avatar-container" in:fly={{ y: -20, duration: 800, delay: 300 }}>
				<img src="/vspsgrad.jpg" alt="Ghislain Kean David Profile" class="avatar" />
				<div class="glow-ring"></div>
			</div>
			
			<div class="identity-info" in:fly={{ y: 20, duration: 800, delay: 450 }}>
				<h1 class="name">Ghislain Kean David</h1>
				<p class="role">
					{currentText}<span class="typing-cursor">|</span>
				</p>
				<p class="bio">Automating processes, optimizing workflows, designing intelligent AI agent pipelines, and building responsive web applications for seamless operational scale.</p>
			</div>
		</div>

			<div class="tech-stack-section">
				<h2 class="section-title">Tech Stack</h2>
				<div class="badge-list">
				{#each allTechs as item}
					<span class="tech-badge" style="--brand-color: {item.color}; --brand-color-glow: {item.colorGlow}">
						{#if item.icon}
							{#if item.icon.startsWith('<svg')}
								{@html item.icon.replace('<svg', '<svg width="14" height="14" class="badge-icon"')}
							{:else if item.icon.startsWith('<img')}
								{@html item.icon.replace('<img', '<img width="14" height="14" style="object-fit:contain"')}
							{:else}
								<svg viewBox="0 0 24 24" class="badge-icon">
									{@html item.icon}
								</svg>
							{/if}
						{/if}
						{item.name}
					</span>
				{/each}
				</div>
			</div>

		<!-- Footer Area: Social Media -->
		<div class="sidebar-footer" in:fly={{ y: 20, duration: 800, delay: 750 }}>
			<div class="social-links">
				{#each socials as social}
					<a href={social.url} target="_blank" rel="noopener noreferrer" class="social-icon {social.class}" aria-label={social.name}>
						<svg viewBox="0 0 24 24" class="svg-icon">
							{@html social.svg}
						</svg>
						<span class="tooltip">{social.tooltip || social.name}</span>
					</a>
				{/each}
			</div>
			<div class="copyright">
				&copy; {new Date().getFullYear()} Ghislain Kean David.
			</div>
		</div>
	</div>
{/if}

<style>
	.sidebar-content {
		display: flex;
		flex-direction: column;
		justify-content: space-between;
		height: 100%;
		gap: 1.5rem;
	}

	.profile-header {
		display: flex;
		flex-direction: column;
		align-items: center;
		text-align: center;
		gap: 1rem;
	}

	.avatar-container {
		position: relative;
		width: 140px;
		height: 140px;
		border-radius: 50%;
		padding: 4px;
		background: linear-gradient(135deg, var(--accent-orange), var(--accent-sand));
	}

	.avatar {
		width: 100%;
		height: 100%;
		object-fit: cover;
		border-radius: 50%;
		background-color: var(--bg-color-sidebar);
		border: 4px solid var(--bg-color-sidebar);
	}

	.glow-ring {
		position: absolute;
		top: 0;
		left: 0;
		right: 0;
		bottom: 0;
		border-radius: 50%;
		box-shadow: 0 0 20px rgba(217, 90, 56, 0.3);
		pointer-events: none;
		animation: pulse-glow 3s infinite alternate ease-in-out;
	}

	@keyframes pulse-glow {
		0% {
			transform: scale(1);
			opacity: 0.4;
		}
		100% {
			transform: scale(1.03);
			opacity: 0.8;
			box-shadow: 0 0 30px rgba(217, 90, 56, 0.55);
		}
	}

	.identity-info {
		display: flex;
		flex-direction: column;
		gap: 0.5rem;
		min-height: 85px;
	}

	.name {
		font-size: 2.1rem;
		color: var(--text-primary);
		font-weight: 800;
		background: linear-gradient(135deg, #ffffff 30%, var(--text-secondary));
		-webkit-background-clip: text;
		-webkit-text-fill-color: transparent;
	}

	.role {
		font-family: var(--font-mono);
		font-size: 0.9rem;
		color: var(--accent-orange);
		font-weight: 600;
		letter-spacing: 0.05em;
		text-transform: uppercase;
		display: flex;
		align-items: center;
		justify-content: center;
	}

	.typing-cursor {
		font-weight: bold;
		animation: blink 0.7s infinite;
		margin-left: 2px;
		color: var(--accent-orange);
	}

	@keyframes blink {
		0%, 100% { opacity: 1; }
		50% { opacity: 0; }
	}

	.bio {
		font-size: 0.85rem;
		color: var(--text-secondary);
		line-height: 1.5;
		margin-top: 0.25rem;
		max-width: 290px;
	}

	.tech-stack-section {
		display: flex;
		flex-direction: column;
		gap: 0.75rem;
	}

	.section-title {
		font-size: 0.75rem;
		text-transform: uppercase;
		letter-spacing: 0.1em;
		color: var(--text-muted);
		font-weight: 700;
		border-bottom: 1px solid var(--border-color);
		padding-bottom: 0.4rem;
	}

	.badge-list {
		display: flex;
		flex-wrap: wrap;
		gap: 0.4rem;
		max-height: 220px;
		overflow-y: auto;
		scrollbar-width: none;
